// UNI-PASS API001 화물통관 진행정보 조회 대상 생성
const trigger = $input.first()?.json || {};
const body = trigger.body || trigger || {};

function asBool(value) {
  if (value === true) return true;
  if (value === false) return false;
  const text = String(value || '').trim().toLowerCase();
  return ['1', 'true', 'yes', 'y', 'dry-run'].includes(text);
}

function normalizeText(value) {
  return String(value || '').trim();
}

function parseEnvQueries(value) {
  const text = String(value || '').trim();
  if (!text) return [];
  try {
    const parsed = JSON.parse(text);
    if (Array.isArray(parsed)) return parsed;
    if (parsed && typeof parsed === 'object') return [parsed];
  } catch (error) {}
  return text.split(/[\n;]+/).map((line) => {
    const item = {};
    for (const part of line.split(',')) {
      const [key, ...rest] = part.split('=');
      if (key && rest.length) item[key.trim()] = rest.join('=').trim();
    }
    if (!Object.keys(item).length) item.cargMtNo = line.trim();
    return item;
  }).filter((item) => Object.values(item).some(Boolean));
}

function normalizeQuery(raw) {
  const item = typeof raw === 'string' ? { cargMtNo: raw } : (raw || {});
  const query = {
    cargMtNo: normalizeText(item.cargMtNo || item.cargoManagementNo || item.cargoNo),
    mblNo: normalizeText(item.mblNo || item.masterBlNo),
    hblNo: normalizeText(item.hblNo || item.houseBlNo),
    blYy: normalizeText(item.blYy || item.blYear || item.year),
  };
  if (!query.cargMtNo && !query.mblNo && !query.hblNo) return null;
  if ((query.mblNo || query.hblNo) && !query.blYy) {
    query.blYy = String(new Date().getFullYear());
  }
  query.lookupKey = query.cargMtNo || [query.blYy, query.mblNo, query.hblNo].filter(Boolean).join('-');
  return query;
}

const requested = body.cargoQueries || body.queries || body.cargMtNos || body.cargMtNo || body.cargoManagementNo;
let rawQueries = [];
if (Array.isArray(requested)) rawQueries = requested;
else if (requested && typeof requested === 'object') rawQueries = [requested];
else if (requested) rawQueries = String(requested).split(/[\n,;\s]+/).filter(Boolean);
else rawQueries = parseEnvQueries($env.UNIPASS_CARGO_QUERIES || '');

const queries = rawQueries.map(normalizeQuery).filter(Boolean);
const dryRun = asBool(body.dryRun || body.preview || $env.UNIPASS_TAX_DRY_RUN);
const now = new Date().toISOString();
const runLabel = String(body.runLabel || body.label || 'manual-or-scheduled').slice(0, 80);
const errors = [];

if (!$env.UNIPASS_API001_CRKYCN) {
  errors.push('UNIPASS_API001_CRKYCN env 미설정');
}
if (queries.length === 0) {
  errors.push('조회할 화물관리번호/BL 없음: body.cargoQueries 또는 UNIPASS_CARGO_QUERIES 필요');
}

if (errors.length > 0) {
  return [{
    json: {
      skip: true,
      stage: 'prepare-clearance',
      dryRun,
      runLabel,
      fetchedAt: now,
      errors,
      message: 'UNI-PASS API001 통관진행 조회 준비 중단: ' + errors.join(' / '),
    }
  }];
}

return queries.map((query) => ({
  json: {
    skip: false,
    sourceApi: 'API001',
    ...query,
    dryRun,
    runLabel,
    fetchedAt: now,
  }
}));

// UNI-PASS API001 XML 응답 파싱
const responses = $input.all();
const requests = $('Prepare Clearance Queries').all().filter((item) => !item.json.skip);

function cleanText(value) {
  return String(value || '')
    .replace(/<!\[CDATA\[/g, '')
    .replace(/\]\]>/g, '')
    .replace(/<[^>]+>/g, '')
    .replace(/\s+/g, ' ')
    .trim();
}

function extractFirst(xml, tag) {
  const re = new RegExp('<\\s*' + tag + '\\s*>([\\s\\S]*?)<\\s*/\\s*' + tag + '\\s*>', 'i');
  const match = String(xml || '').match(re);
  return match ? cleanText(match[1]) : '';
}

function extractBlocks(xml, tag) {
  const re = new RegExp('<\\s*' + tag + '\\s*>([\\s\\S]*?)<\\s*/\\s*' + tag + '\\s*>', 'gi');
  const blocks = [];
  let match;
  while ((match = re.exec(String(xml || ''))) !== null) {
    blocks.push(match[1]);
  }
  return blocks;
}

function parseDetail(block) {
  return {
    processType: extractFirst(block, 'cargTrcnRelaBsopTpcd'),
    processedAt: extractFirst(block, 'prcsDttm'),
    releaseAt: extractFirst(block, 'rlbrDttm'),
    releaseContent: extractFirst(block, 'rlbrCn'),
    declarationNo: extractFirst(block, 'dclrNo'),
    warehouseCode: extractFirst(block, 'shedSgn'),
    warehouseName: extractFirst(block, 'shedNm'),
    basisNo: extractFirst(block, 'rlbrBssNo'),
  };
}

function normalizeDeclarationNo(value) {
  return String(value || '').replace(/[^0-9A-Za-z]/g, '').trim();
}

const rows = responses.map((item, index) => {
  const req = requests[index]?.json || {};
  const xml = String(item.json.data || item.json.body || item.json || '');
  const tCnt = extractFirst(xml, 'tCnt');
  const notice = extractFirst(xml, 'ntceInfo');
  const details = extractBlocks(xml, 'cargCsclPrgsInfoDtlQryVo').map(parseDetail);
  const declarationNo = normalizeDeclarationNo(details.map((d) => d.declarationNo).find(Boolean) || extractFirst(xml, 'dclrNo'));
  const shouldStoreRaw = String($env.UNIPASS_STORE_RAW_XML || '').toLowerCase() === 'true';

  return {
    sourceApi: 'API001',
    lookupKey: req.lookupKey || '',
    cargoManagementNo: extractFirst(xml, 'cargMtNo') || req.cargMtNo || '',
    mblNo: extractFirst(xml, 'mblNo') || req.mblNo || '',
    hblNo: extractFirst(xml, 'hblNo') || req.hblNo || '',
    blYear: req.blYy || '',
    progressStatus: extractFirst(xml, 'prgsStts'),
    progressCode: extractFirst(xml, 'prgsStCd'),
    customsProgressStatus: extractFirst(xml, 'csclPrgsStts'),
    importDeclarationNo: declarationNo,
    productName: extractFirst(xml, 'prnm'),
    entryDate: extractFirst(xml, 'etprDt'),
    processedAt: extractFirst(xml, 'prcsDttm'),
    detailCount: details.length,
    latestDetail: details[0] || {},
    notice,
    tCnt,
    success: Number(tCnt || 0) > 0 || !!extractFirst(xml, 'cargMtNo') || details.length > 0,
    dryRun: !!req.dryRun,
    runLabel: req.runLabel || '',
    fetchedAt: req.fetchedAt || new Date().toISOString(),
    rawXml: shouldStoreRaw ? xml : '',
  };
});

return rows.map((row) => ({ json: row }));

// API001 결과를 NocoDB customs_clearance_status 테이블에 upsert
const rows = $input.all().map((item) => item.json);
const dryRun = rows.some((row) => row.dryRun);
const token = $env.NOCODB_API_TOKEN || $env.NOCODB_TOKEN || $env.NOCODB_API_TOKEN_CLAUDE_SESSION || '';
const baseId = $env.NOCODB_BASE_ID || 'pu0mwk97kac8a5p';
const tableId = $env.NOCODB_CUSTOMS_CLEARANCE_STATUS_TABLE_ID || '';
const baseUrl = 'https://nocodb.pressco21.com/api/v1/db/data/noco/' + baseId + '/' + tableId;

function compact(value, max = 700) {
  return String(value || '').slice(0, max);
}

function keyFor(row) {
  return row.cargoManagementNo || row.lookupKey || [row.blYear, row.mblNo, row.hblNo].filter(Boolean).join('-');
}

function rowToPayload(row) {
  const detail = row.latestDetail || {};
  const payload = {
    source_api: 'API001',
    lookup_key: keyFor(row),
    cargo_management_no: row.cargoManagementNo || '',
    mbl_no: row.mblNo || '',
    hbl_no: row.hblNo || '',
    bl_year: row.blYear || '',
    progress_status: row.progressStatus || '',
    progress_code: row.progressCode || '',
    customs_progress_status: row.customsProgressStatus || '',
    import_declaration_no: row.importDeclarationNo || '',
    product_name: compact(row.productName || '', 300),
    entry_date: row.entryDate || '',
    processed_at: row.processedAt || '',
    latest_process_type: detail.processType || '',
    latest_release_content: compact(detail.releaseContent || '', 500),
    latest_release_at: detail.releaseAt || '',
    warehouse_name: compact(detail.warehouseName || '', 300),
    detail_count: String(row.detailCount || 0),
    notice: compact(row.notice || ''),
    t_cnt: row.tCnt || '',
    fetched_at: row.fetchedAt,
    run_label: row.runLabel || '',
    last_result: row.success ? 'success' : 'empty_or_error',
  };
  if (row.rawXml) payload.raw_xml = row.rawXml;
  return payload;
}

async function request(method, url, body) {
  return await this.helpers.httpRequest({
    method,
    url,
    headers: {
      'xc-token': token,
      'Content-Type': 'application/json',
    },
    body,
    json: true,
    timeout: 20000,
  });
}

const summary = {
  sourceApi: 'API001',
  dryRun,
  total: rows.length,
  success: rows.filter((row) => row.success).length,
  emptyOrError: rows.filter((row) => !row.success).length,
  persisted: 0,
  updated: 0,
  created: 0,
  skipped: 0,
  errors: [],
  rows,
  fetchedAt: new Date().toISOString(),
};

if (dryRun || !token || !tableId) {
  summary.skipped = rows.length;
  if (!token) summary.errors.push('NOCODB_API_TOKEN 또는 NOCODB_TOKEN env 미설정');
  if (!tableId) summary.errors.push('NOCODB_CUSTOMS_CLEARANCE_STATUS_TABLE_ID env 미설정');
  if (dryRun) summary.errors.push('dryRun=true: NocoDB 저장 생략');
  return [{ json: summary }];
}

for (const row of rows) {
  const lookupKey = keyFor(row);
  if (!lookupKey) {
    summary.skipped += 1;
    summary.errors.push('lookup_key 없는 row 저장 생략');
    continue;
  }
  const where = encodeURIComponent('(lookup_key,eq,' + lookupKey + ')');
  try {
    const found = await request.call(this, 'GET', baseUrl + '?limit=1&where=' + where);
    const existing = Array.isArray(found?.list) ? found.list[0] : null;
    const payload = rowToPayload(row);
    if (existing?.Id) {
      await request.call(this, 'PATCH', baseUrl + '/' + existing.Id, payload);
      summary.updated += 1;
    } else {
      await request.call(this, 'POST', baseUrl, payload);
      summary.created += 1;
    }
    summary.persisted += 1;
  } catch (error) {
    summary.errors.push(lookupKey + ': ' + (error.message || String(error)));
  }
}

return [{ json: summary }];

// API001 실행 요약 텔레그램 메시지 생성
const data = $input.first()?.json || {};
const rows = data.rows || [];
function esc(value) {
  return String(value ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}
function mask(value) {
  const text = String(value || '');
  if (text.length <= 8) return text;
  return text.slice(0, 5) + '…' + text.slice(-3);
}
let text = '<b>관세청 화물통관 진행조회</b>\n';
text += '결과: ' + esc(data.persisted ? 'NocoDB 저장 완료' : '조회 완료/저장 생략') + '\n';
text += '조회 ' + esc(data.total ?? rows.length) + '건 · 조회성공 ' + esc(data.success ?? 0) + '건 · 미확인/오류 ' + esc(data.emptyOrError ?? 0) + '건\n';
text += '저장 ' + esc(data.persisted || 0) + '건 (신규 ' + esc(data.created || 0) + ', 수정 ' + esc(data.updated || 0) + ')\n';
if (data.dryRun) text += '모드: dry-run\n';
if (data.errors && data.errors.length) {
  text += '\n<b>확인 필요</b>\n' + data.errors.slice(0, 5).map((e) => '- ' + esc(e)).join('\n') + '\n';
}
if (rows.length) {
  text += '\n<b>대상</b>\n' + rows.slice(0, 8).map((row) => '- ' + esc(mask(row.cargoManagementNo || row.lookupKey)) + ': ' + esc(row.progressStatus || '-') + ' / 신고번호 ' + esc(mask(row.importDeclarationNo || '-'))).join('\n');
  if (rows.length > 8) text += '\n외 ' + (rows.length - 8) + '건';
}
return [{ json: { chatId: '7713811206', message: text, summary: data } }];

// 준비 단계에서 중단된 경우 텔레그램 메시지 생성
const data = $input.first()?.json || {};
function esc(value) {
  return String(value ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}
const errors = Array.isArray(data.errors) ? data.errors : [data.message || '알 수 없는 준비 오류'];
const text = '<b>관세청 자동화 준비 중단</b>\n' + errors.map((e) => '- ' + esc(e)).join('\n');
return [{ json: { chatId: '7713811206', message: text, summary: data } }];
